package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;

class CSVFormatTest {

    @Test
    void testWithAllowMissingColumnNames() throws Exception {
        CSVFormat original = CSVFormat.DEFAULT;
        assertFalse(original.getAllowMissingColumnNames());

        CSVFormat updated = original.withAllowMissingColumnNames();
        assertNotNull(updated);
        assertTrue(updated.getAllowMissingColumnNames());

        // Ensure original is not modified (immutability)
        assertFalse(original.getAllowMissingColumnNames());

        // Also test withAllowMissingColumnNames(boolean) for completeness
        CSVFormat updatedFalse = original.withAllowMissingColumnNames(false);
        assertNotNull(updatedFalse);
        assertFalse(updatedFalse.getAllowMissingColumnNames());
        assertNotSame(updated, updatedFalse);
    }
}
